using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    private IQueryable<string> CreateTestSource(int count)
    {
        return Enumerable.Range(1, count).Select(i => $"Item{i}").AsQueryable();
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = CreateTestSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual("Item1", result[0]);
        Assert.AreEqual("Item10", result[9]);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = CreateTestSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual("Item11", result[0]);
        Assert.AreEqual("Item20", result[9]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = CreateTestSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 3, 10);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual("Item21", result[0]);
        Assert.AreEqual("Item25", result[4]);
    }

    [TestMethod]
    public void Create_CalculatesTotalPagesCorrectly()
    {
        // Arrange
        var source = CreateTestSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void Create_ExactMultiple_CalculatesTotalPagesCorrectly()
    {
        // Arrange — 20 items / 10 per page = 2 pages exactly
        var source = CreateTestSource(20);

        // Act
        var result = PaginatedList<string>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(2, result.TotalPages);
    }

    [TestMethod]
    public void Create_SingleItem_OnePage()
    {
        // Arrange
        var source = CreateTestSource(1);

        // Act
        var result = PaginatedList<string>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.TotalPages);
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual("Item1", result[0]);
    }

    [TestMethod]
    public void PageIndex_ReflectsRequestedPage()
    {
        // Arrange
        var source = CreateTestSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        // Arrange
        var source = CreateTestSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 1, 10);

        // Assert
        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        // Arrange
        var source = CreateTestSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 2, 10);

        // Assert
        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // Arrange
        var source = CreateTestSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 3, 10);

        // Assert
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_FirstPage_ReturnsTrue()
    {
        // Arrange
        var source = CreateTestSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 1, 10);

        // Assert
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_MiddlePage_ReturnsTrue()
    {
        // Arrange
        var source = CreateTestSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 2, 10);

        // Assert
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Constructor_SetsProperties()
    {
        // Arrange
        var items = new List<int> { 1, 2, 3 };

        // Act
        var result = new PaginatedList<int>(items, 30, 2, 10);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(2, result[1]);
        Assert.AreEqual(3, result[2]);
    }

    [TestMethod]
    [DataRow(1, 10, false, true, DisplayName = "First page: no prev, has next")]
    [DataRow(2, 10, true, true, DisplayName = "Middle page: has prev and next")]
    [DataRow(3, 10, true, false, DisplayName = "Last page: has prev, no next")]
    public void Create_NavigationFlags_CorrectForVariousPages(int pageIndex, int pageSize, bool expectedPrev, bool expectedNext)
    {
        // Arrange
        var source = CreateTestSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, pageIndex, pageSize);

        // Assert
        Assert.AreEqual(expectedPrev, result.HasPreviousPage);
        Assert.AreEqual(expectedNext, result.HasNextPage);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
