        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteWithDisplayName_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_CreateWithoutDisplayName_GeneratesMessageWithId()
    {
