        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_DrainsQueue_ReturnsNullAfterAllConsumed()
    {
        // Arrange
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        _sut.SendNotification("Student", "2", EntityOperation.CREATE);

