    {
        // Arrange
        var source = CreateTestSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual("Item11", result[0]);
        Assert.AreEqual("Item20", result[9]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
