using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using ContosoUniversity.Data;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();
        _controller = new NotificationsController(_context);

        // Drain any stale notifications from the static queue
        var drainService = new NotificationService();
        while (drainService.ReceiveNotification() != null) { }
        drainService.Dispose();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    // ==================== Index Tests ====================

    [TestMethod]
    public void Index_ReturnsView()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // ==================== GetNotifications Tests ====================

    [TestMethod]
    public void GetNotifications_WhenEmpty_ReturnsSuccessWithEmptyList()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);

        // Use reflection to check anonymous type properties
        var successProp = value.GetType().GetProperty("success");
        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(successProp);
        Assert.IsNotNull(countProp);
        Assert.AreEqual(true, successProp.GetValue(value));
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange — send some notifications via a NotificationService
        var service = new NotificationService();
        service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");
        service.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE, "Admin");
        service.Dispose();

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        var successProp = value.GetType().GetProperty("success");
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(true, successProp.GetValue(value));
        Assert.AreEqual(2, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_LimitsTen()
    {
        // Arrange — send 15 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }
        service.Dispose();

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var value = result.Value;
        Assert.IsNotNull(value);
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(10, countProp.GetValue(value)); // Limited to 10
    }

    // ==================== MarkAsRead Tests ====================

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_NonExistentId_StillReturnsSuccess()
    {
        // Act — MarkAsRead is a no-op in the in-memory implementation
        var result = _controller.MarkAsRead(99999);

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }
