    {
        // Arrange & Act
        using var context = TestDbContextFactory.Create();

        // Assert
        Assert.IsNotNull(context);
        Assert.IsNotNull(context.Students);
        Assert.IsNotNull(context.Courses);
        Assert.IsNotNull(context.Departments);
        Assert.IsNotNull(context.Instructors);
        Assert.IsNotNull(context.Enrollments);
        Assert.IsNotNull(context.OfficeAssignments);
        Assert.IsNotNull(context.CourseAssignments);
        Assert.IsNotNull(context.People);
        Assert.IsNotNull(context.Notifications);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveStudent()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2024-01-01")
        };

        // Act
        context.Students.Add(student);
        context.SaveChanges();

        // Assert
        var retrieved = context.Students.FirstOrDefault(s => s.LastName == "Student");
        Assert.IsNotNull(retrieved);
        Assert.AreEqual("Test", retrieved.FirstMidName);
        Assert.AreEqual("Student", retrieved.LastName);
        Assert.AreEqual(DateTime.Parse("2024-01-01"), retrieved.EnrollmentDate);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveCourse()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        context.Departments.Add(new Department
        {
            DepartmentID = 1,
            Name = "Test Dept",
            Budget = 100000m,
            StartDate = DateTime.Parse("2024-01-01")
        });
        context.SaveChanges();

        var course = new Course
        {
            CourseID = 5000,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = 1
        };

        // Act
        context.Courses.Add(course);
        context.SaveChanges();

        // Assert
        var retrieved = context.Courses.Find(5000);
        Assert.IsNotNull(retrieved);
        Assert.AreEqual("Test Course", retrieved.Title);
        Assert.AreEqual(3, retrieved.Credits);
    }

    [TestMethod]
    public void SchoolContext_CourseAssignment_HasCompositeKey()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Add instructor, department, course
        context.Instructors.Add(new Instructor
        {
            ID = 1, FirstMidName = "Test", LastName = "Prof",
            HireDate = DateTime.Parse("2020-01-01")
        });
        context.Departments.Add(new Department
        {
            DepartmentID = 1, Name = "Test", Budget = 100000m,
            StartDate = DateTime.Parse("2020-01-01")
        });
        context.SaveChanges();
        context.Courses.Add(new Course
        {
            CourseID = 1000, Title = "Test", Credits = 3, DepartmentID = 1
        });
        context.SaveChanges();

        // Act — add CourseAssignment with composite key
        context.CourseAssignments.Add(new CourseAssignment
        {
            CourseID = 1000,
            InstructorID = 1
        });
        context.SaveChanges();

        // Assert
        var assignment = context.CourseAssignments
            .FirstOrDefault(ca => ca.CourseID == 1000 && ca.InstructorID == 1);
        Assert.IsNotNull(assignment);
    }

    [TestMethod]
    public void SchoolContext_TPH_DiscriminatesStudentsAndInstructors()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        context.Students.Add(new Student
        {
            ID = 100, FirstMidName = "Stu", LastName = "Dent",
            EnrollmentDate = DateTime.Parse("2020-01-01")
        });
        context.Instructors.Add(new Instructor
        {
            ID = 200, FirstMidName = "In", LastName = "Structor",
            HireDate = DateTime.Parse("2020-01-01")
        });
        context.SaveChanges();

        // Act
        var students = context.Students.ToList();
        var instructors = context.Instructors.ToList();

        // Assert — each set only returns its type
        Assert.AreEqual(1, students.Count);
        Assert.AreEqual("Dent", students[0].LastName);
        Assert.AreEqual(1, instructors.Count);
        Assert.AreEqual("Structor", instructors[0].LastName);
    }

    [TestMethod]
    public void SchoolContext_CanDeleteEntity()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var student = new Student
        {
            FirstMidName = "ToDelete",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2024-01-01")
        };
        context.Students.Add(student);
        context.SaveChanges();
        var id = student.ID;

        // Act
        context.Students.Remove(student);
        context.SaveChanges();

        // Assert
        Assert.IsNull(context.Students.Find(id));
    }

    [TestMethod]
    public void SchoolContext_CanUpdateEntity()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var department = new Department
        {
            DepartmentID = 99,
            Name = "Original",
            Budget = 100000m,
            StartDate = DateTime.Parse("2024-01-01")
        };
        context.Departments.Add(department);
        context.SaveChanges();

        // Act
        department.Name = "Updated";
        department.Budget = 200000m;
        context.SaveChanges();

        // Assert
        var updated = context.Departments.Find(99);
        Assert.AreEqual("Updated", updated.Name);
        Assert.AreEqual(200000m, updated.Budget);
    }
}

